    if not isinstance(event_details, dict):
        raise ValueError("Event details must be a dictionary.")

    required_keys = ['event_name', 'start_time', 'end_time', 'vc_room']
    for key in required_keys:
        if key not in event_details:
            raise ValueError(f"Missing required key: {key}")

    event_name = event_details['event_name']
    start_time = event_details['start_time']
    end_time = event_details['end_time']
    vc_room = event_details['vc_room']

    if not isinstance(event_name, str) or not event_name:
        raise ValueError("Event name must be a non-empty string.")

    if not isinstance(start_time, str) or not isinstance(end_time, str):
        raise ValueError("Start time and end time must be strings.")

    if start_time >= end_time:
        raise ValueError("Start time must be before end time.")

